    "বারহাট্টা (নেত্রকোণা)", "দুর্গাপুর (নেত্রকোণা)", "কেন্দুয়া (নেত্রকোণা)", "আটপাড়া (নেত্রকোণা)", "মদন (নেত্রকোণা)", "খালিয়াজুরী (নেত্রকোণা)", "কলমাকান্দা (নেত্রকোণা)", "মোহনগঞ্জ (নেত্রকোণা)", "পূর্বধলা (নেত্রকোণা)", "নেত্রকোণা সদর (নেত্রকোণা)",
  ];

  /// District -> Upazila names
  static late final Map<String, List<String>> districtToUpazilas = _buildDistrictToUpazilasMap(upazilas);

  static Map<String, List<String>> _buildDistrictToUpazilasMap(List<String> items) {
    final map = <String, List<String>>{};

    for (final raw in items) {
      final s = raw.trim();
      if (s.isEmpty) continue;

      final open = s.lastIndexOf('(');
      final close = s.lastIndexOf(')');

      if (open == -1 || close == -1 || close < open) continue;

      final name = s.substring(0, open).trim();
      final district = s.substring(open + 1, close).trim();

      if (name.isEmpty || district.isEmpty) continue;

      map.putIfAbsent(district, () => <String>[]);
      map[district]!.add(name);
    }

    map.forEach((k, v) {
      final uniq = v.toSet().toList()..sort();
      map[k] = uniq;
    });

    return map;
  }

  /// Division -> District -> Upazila
  static late final Map<String, Map<String, List<String>>> divisionDistrictUpazila = _buildDivisionDistrictUpazila();

  static Map<String, Map<String, List<String>>> _buildDivisionDistrictUpazila() {
    final result = <String, Map<String, List<String>>>{};

    divisionToDistricts.forEach((division, districts) {
      final districtMap = <String, List<String>>{};
      for (final d in districts) {
        districtMap[d] = districtToUpazilas[d] ?? <String>[];
      }
      result[division] = districtMap;
    });

    return result;
  }
}